namespace BlazorApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<Notification> _notifications =
    [
        new() { Id = 1, Message = "Welcome to the app!", Timestamp = DateTime.Now.AddMinutes(-30) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.Now.AddMinutes(-15) },
        new() { Id = 3, Message = "New feature available: Dark Mode.", Timestamp = DateTime.Now.AddMinutes(-5) },
    ];

    private static readonly string[] SampleMessages =
    [
        "You have a new follower.",
        "Your report is ready to download.",
        "Scheduled maintenance tonight at 11 PM.",
        "Someone commented on your post.",
        "Your subscription will renew soon.",
        "A new update is available.",
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        return Task.FromResult(_notifications.ToList());
    }

    public Task<List<Notification>> GetNewNotificationsSinceAsync(int lastId)
    {
        // Simulate occasional new notifications
        if (Random.Shared.Next(3) == 0)
        {
            var msg = SampleMessages[Random.Shared.Next(SampleMessages.Length)];
            _notifications.Add(new Notification
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.Now
            });
        }

        var newer = _notifications.Where(n => n.Id > lastId).ToList();
        return Task.FromResult(newer);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? Notifications { get; set; }

    private List<Notification> notifications => Notifications ?? [];

    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        Notifications ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct).ConfigureAwait(false);

            var lastId = Notifications?.Count > 0 ? Notifications.Max(n => n.Id) : 0;
            var newer = await NotificationService.GetNewNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                Notifications!.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

